const { createHash } = require('crypto');
const fs = require('fs').promises;
const path = require('path');

class CouponRedemptionSystem {
  constructor() {
    this.couponsFile = path.join(__dirname, 'coupons.json');
    this.redemptionsFile = path.join(__dirname, 'redemptions.json');
    this.locks = new Map();
  }

  async initialize() {
    try {
      await fs.access(this.couponsFile);
    } catch {
      await fs.writeFile(this.couponsFile, JSON.stringify({}));
    }
    try {
      await fs.access(this.redemptionsFile);
    } catch {
      await fs.writeFile(this.redemptionsFile, JSON.stringify({}));
    }
  }

  async getCoupon(code) {
    const coupons = JSON.parse(await fs.readFile(this.couponsFile, 'utf8'));
    return coupons[code];
  }

  async updateCoupon(code, updateData) {
    const coupons = JSON.parse(await fs.readFile(this.couponsFile, 'utf8'));
    coupons[code] = { ...coupons[code], ...updateData };
    await fs.writeFile(this.couponsFile, JSON.stringify(coupons, null, 2));
  }

  async getRedemptions() {
    try {
      const redemptions = JSON.parse(await fs.readFile(this.redemptionsFile, 'utf8'));
      return redemptions;
    } catch {
      return {};
    }
  }

  async addRedemption(userId, code) {
    const redemptions = await this.getRedemptions();
    redemptions[userId] = redemptions[userId] || [];
    redemptions[userId].push({ code, timestamp: Date.now() });
    await fs.writeFile(this.redemptionsFile, JSON.stringify(redemptions, null, 2));
  }

  async isUserRedeemed(userId, code) {
    const redemptions = await this.getRedemptions();
    const userRedemptions = redemptions[userId] || [];
    return userRedemptions.some(r => r.code === code);
  }

  async redeemCoupon(userId, code, amount) {
    const lockKey = `coupon_${code}`;
    
    // Simple lock implementation using Map
    if (this.locks.has(lockKey)) {
      return { success: false, error: 'Coupon is being processed' };
    }
    
    this.locks.set(lockKey, true);
    
    try {
      const coupon = await this.getCoupon(code);
      
      if (!coupon) {
        return { success: false, error: 'Coupon not found' };
      }
      
      if (coupon.expiry < Date.now()) {
        return { success: false, error: 'Coupon has expired' };
      }
      
      if (coupon.used) {
        return { success: false, error: 'Coupon has already been used' };
      }
      
      if (await this.isUserRedeemed(userId, code)) {
        return { success: false, error: 'Coupon already used by user' };
      }
      
      // Atomic update of coupon
      await this.updateCoupon(code, { used: true });
      
      // Record redemption
      await this.addRedemption(userId, code);
      
      const discount = (amount * coupon.discount) / 100;
      const finalAmount = amount - discount;
      
      return {
        success: true,
        discount: discount,
        finalAmount: finalAmount,
        originalAmount: amount
      };
    } finally {
      this.locks.delete(lockKey);
    }
  }
}

